INSERT INTO `personajes` (`id`, `nombrereal`, `personaje`, `altura`, `peso`, `poderes`, `sexo`, `debilidad`, `creation`, `biografia`, `imagen`) VALUES
(1, 'Peter Parker', 'Spiderman', 178, 73, 'Capacidad de adherirse a superficies sólidas (trepar paredes), un \"sentido arácnido\" precognitivo que lo alerta del peligro, y una curación acelerada.', 'masculino', 'Cloruro de etilo, un compuesto químico que puede a', '1962-08-03', 'Spider-Man, creado por Stan Lee y Steve Ditko en 1962, es la identidad secreta de Peter Parker, un adolescente huérfano de Queens, Nueva York, criado por sus tíos Ben y May. Tras ser mordido por una araña radiactiva, obtuvo habilidades sobrehumanas (fuerza, agilidad, trepar paredes, sentido arácnido). Asumió el heroísmo tras la muerte de su tío Ben por no detener a un ladrón, aprendiendo que \"un gran poder conlleva una gran responsabilidad\". ', );
INSERT INTO `personajes` (`id`, `nombrereal`, `personaje`, `altura`, `peso`, `poderes`, `sexo`, `debilidad`, `creation`, `biografia`, `imagen`) VALUES
(2, 'Benjamin Kirby \"Ben\" Tennyson', 'Ben', 178, 59, 'pirocinesis (Heatblast), súper fuerza (Four Arms), control de tiempo (Clockwork), manipulación de energía (Feedback) y alteración de la realidad (Alien X).', 'masculino', 'Ben 10\'s primary weakness is the Omnitrix\'s timeou', '2005-12-27', 'Benjamin Kirby \"Ben\" Tennyson is the 10-year-old protagonist of the Ben 10 franchise who gains the ability to transform into various aliens using the Omnitrix. During a summer road trip with his cousin Gwen and Grandpa Max, he finds the device, evolving from an immature kid into a heroic, renowned defender of Earth and the universe by age 16.', );
INSERT INTO `personajes` (`id`, `nombrereal`, `personaje`, `altura`, `peso`, `poderes`, `sexo`, `debilidad`, `creation`, `biografia`, `imagen`) VALUES
(3, 'Bill Cipher', 'Bill Cipher', 160, 0, 'Posee poderes como la magia, el control mental, la manipulación de la realidad y los viajes interdimensionales.', 'masculino', 'La principal debilidad de Bill Cipher es su depend', '2013-07-12', 'Bill Cipher, created by Alex Hirsch, is a central antagonist in the Disney Channel series \"Gravity Falls.\" His creation began as a joke within the production team, drawing inspiration from the American Ojo de la Providencia symbol on U.S. currency. Over time, Bill evolved into a character that would become a formidable foe within the series, embodying a sense of extraordinary evil. Hirsch\'s involvement in the series, including his work on \"Flapjack,\" led to his contact with Disney for a potential \"Gravity Falls\" project, which ultimately resulted in the creation of Bill Cipher', ),
(4, 'Bruce Wayne', 'Batman', 190, 95, 'Batman no posee superpoderes, pero tiene habilidades extraordinarias, incluyendo un acondicionamiento físico al máximo nivel humano, una inteligencia excepcional y una gran variedad de artilugios.', 'masculino', ' Sin embargo, su psicología y emociones también so', '1939-03-30', 'Batman, creado por Bob Kane y Bill Finger, es un superhéroe ficticio de cómic y propiedad de DC Comics. Apareció por primera vez en la historia titulada \"El caso del sindicato químico\" de la revista Detective Comics N.º 27, lanzada por la editorial National Publications el 30 de marzo de 1939. La identidad secreta de Batman es Bruce Wayne, un multimillonario magnate empresarial y filántropo dueño de Empresas Wayne en Gotham City. Después de presenciar el asesinato de sus padres, el Dr. Thomas Wayne y Martha Wayne, Bruce juró venganza contra los criminales, un juramento moderado por el sentido de la justicia. Batman se entrena física e intelectualmente y crea un traje inspirado en los murciélagos para combatir el crimen, con sus gadgets de combate del batcinturón y sus vehículos. A diferencia de los superhéroes, no tiene superpoderes: recurre a su intelecto, así como a aplicaciones científicas y tecnológicas para crear armas y herramientas con las cuales lleva a cabo sus actividades. ', );
INSERT INTO `personajes` (`id`, `nombrereal`, `personaje`, `altura`, `peso`, `poderes`, `sexo`, `debilidad`, `creation`, `biografia`, `imagen`) VALUES
(5, 'Wade Wilson', 'Deadpool', 193, 95, 'Factor Regenerativo: Curación instantánea de heridas y daños, lo que le otorga una especie de inmortalidad. Sin embargo, su cáncer terminal lo mantiene a raya gracias a su regeneración. \r\n1\r\nFuerza sobrehumana: Capacidad de levantar cargas superiores a las capacidades humanas normales. \r\n1\r\nVelocidad humana máxima: Movimientos ágiles y reacción rápida, lo que le permite esquivar proyectiles y sorprender a sus enemigos. \r\n1\r\nResistencia sobrehumana: Capacidad de resistir impactos mortales y ataqu', 'masculino', 'Cura para el cáncer: Una cura para su cáncer termi', '1991-02-05', 'Deadpool hizo su primera aparición en New Mutants #98 en 1991. Originalmente, fue concebido como un villano que se enfrentaba a los jóvenes mutantes, pero con el tiempo se transformó en un antihéroe popular. Su historia comienza con Wade Wilson, un mercenario que, tras ser diagnosticado con cáncer, se ofrece como voluntario para el Proyecto Arma X, un experimento que le otorga habilidades sobrehumanas, pero también lo deja desfigurado y con problemas mentales. \r\n', );

